import React from 'react';

function Trade(props) {


    return(
        <div>
            {props.trade.stock}
            <span className='buffer'></span>
            <span className='tradeTable-spacer'>{props.trade.method}</span>
            <span className='buffer'></span>
            {props.trade.quantity}
            <span className='buffer'></span>
            {props.trade.profitLoss}
            <span className='buffer'></span>
            <button>X</button>
            
        </div>
    )
}

export default Trade;
